// Campuses / external units present in the source data (EXT column).
export const MSU_CAMPUSES = ["Marawi","Basilan","Bataraza","General Santos","Iligan","Maguindanao","Sindangan","Sulu","Tawi-Tawi"];

// Flat list of college codes (backward compatible with the previous COLLEGES export).
export const COLLEGES = MSU_COLLEGES.map((c) => c.code);

const byCode = Object.fromEntries(MSU_COLLEGES.map((c) => [c.code, c]));
const byName = Object.fromEntries(MSU_COLLEGES.map((c) => [c.name, c]));

// Accepts a college code ("CICS") or full name ("College of Information and Computing Sciences").
export function getCollege(collegeRef) {
  if (!collegeRef) return null;
  return byCode[collegeRef] || byName[collegeRef] || null;
}

export function getCollegeName(collegeRef) {
  const c = getCollege(collegeRef);
  return c ? c.name : collegeRef || '';
}

export function getCollegeCode(collegeRef) {
  const c = getCollege(collegeRef);
  return c ? c.code : collegeRef || '';
}

// Departments for a given college (code or name). Returns [{ code, name, programs }].
export function getDepartments(collegeRef) {
  const c = getCollege(collegeRef);
  return c ? c.departments : [];
}

// Programs/courses for a given college + department (each accepts code or name).
export function getPrograms(collegeRef, departmentRef) {
  const depts = getDepartments(collegeRef);
  const d = depts.find((x) => x.code === departmentRef || x.name === departmentRef);
  return d ? d.programs : [];
}

export function getDepartment(collegeRef, departmentRef) {
  const depts = getDepartments(collegeRef);
  return depts.find((x) => x.code === departmentRef || x.name === departmentRef) || null;
}
